import React from "react";
import { safeGet, safeArray, safeObject } from "../utils/helpers";

/* ===========================
   BILL CONTENT COMPONENT
=========================== */

const BillContent = ({ data, index = 0 }) => {
  const header = safeObject(data.header);

  let rawItems = data.items_json;
  if (!rawItems || rawItems.length === 0) {
    rawItems = data.items;
  }

  const items = safeArray(rawItems);

  const billNumber =
    safeGet(header, "bill_number") ||
    safeGet(data, "bill_number", "N/A");

  const tableNo =
    safeGet(header, "table_no") ||
    safeGet(data, "table_no", "N/A");

  const hotelName = safeGet(data, "hotel_name", "Restaurant");
  const address = safeGet(data, "address", "");
  const phone = safeGet(data, "phone", "");
  const gstin = safeGet(data, "gstin", "");

  const createdAt =
    safeGet(data, "created_at") ||
    safeGet(data, "bill_date", null);

  const subtotal = safeGet(data, "subtotal", 0);
  const sgst = safeGet(data, "sgst", 0);
  const cgst = safeGet(data, "cgst", 0);
  const grandTotal = safeGet(data, "grand_total", 0);

  return (
    <div
      className="print-receipt"
      style={{
        fontFamily: "monospace",
        fontSize: "12px",
        color: "black",
        background: "white",
        padding: "10px"
      }}
    >
      <div className="text-center font-bold">
        {hotelName} [Bill: {billNumber}]
      </div>

      {address && <div className="text-center text-xs">{address}</div>}

      <div className="text-center text-xs">
        GST Included {gstin ? `GSTIN: ${gstin}` : ""}
        {phone ? ` | Ph: ${phone}` : ""}
      </div>

      <div className="text-center">{"=".repeat(40)}</div>

      <div className="flex justify-between">
        <span>Bill No</span>
        <span>{billNumber}</span>
      </div>

      <div className="flex justify-between">
        <span>Date</span>
        <span>
          {createdAt
            ? new Date(createdAt).toLocaleString()
            : "N/A"}
        </span>
      </div>

      <div className="flex justify-between">
        <span>Table</span>
        <span>{tableNo}</span>
      </div>

      <div>{"=".repeat(40)}</div>

      <table style={{ width: "100%" }}>
        <thead>
          <tr>
            <th align="left">No</th>
            <th align="left">Item</th>
            <th align="left">Qty</th>
            <th align="left">Amt</th>
          </tr>
        </thead>
        <tbody>
          {items.length === 0 ? (
            <tr>
              <td colSpan="4" align="center">
                No Items
              </td>
            </tr>
          ) : (
            items.map((item, i) => {
              let name =
                item.item_name ||
                item.name ||
                "Unknown";

              let qty =
                item.quantity ||
                item.qty ||
                0;

              const amount =
                item.line_total ||
                item.amount ||
                0;

              if (!qty && amount) {
                qty = 1;
              }

              return (
                <tr key={i}>
                  <td>{i + 1}</td>
                  <td>{name}</td>
                  <td>{qty}</td>
                  <td>{Number(amount).toFixed(2)}</td>
                </tr>
              );
            })
          )}
        </tbody>
      </table>

      <div>{"=".repeat(40)}</div>

      <div className="flex justify-between">
        <span>Subtotal</span>
        <span>{Number(subtotal).toFixed(2)}</span>
      </div>

      <div className="flex justify-between">
        <span>SGST (2.5%)</span>
        <span>{Number(sgst).toFixed(2)}</span>
      </div>

      <div className="flex justify-between">
        <span>CGST (2.5%)</span>
        <span>{Number(cgst).toFixed(2)}</span>
      </div>

      <div className="flex justify-between font-bold">
        <span>Total</span>
        <span>
          {Math.round(Number(grandTotal)).toFixed(2)}
        </span>
      </div>

      <div className="text-center mt-2">
        Thank you! Visit again
      </div>
    </div>
  );
};

/* ===========================
   BILL PRINT COMPONENT
=========================== */

export default function BillPrint({ billData = null }) {
  const data =
    billData ||
    (typeof window !== "undefined" &&
      window.printBillData) ||
    null;

  if (!data) {
    return <div>No bill data</div>;
  }

  /* ===========================
     SPLIT BILL MODE
     → PRINT EXACTLY 2 BILLS
  ============================ */

  if (
    data.split === true &&
    Array.isArray(data.bills) &&
    data.bills.length > 0
  ) {
    return (
      <div>
        {data.bills.slice(0, 2).map((bill, index) => (
          <div
            key={index}
            style={{
              pageBreakAfter:
                index === 0 ? "always" : "auto"
            }}
          >
            <BillContent
              data={bill}
              index={index}
            />
          </div>
        ))}
      </div>
    );
  }

  /* ===========================
     NORMAL BILL MODE
     → PRINT SINGLE BILL
  ============================ */

  return <BillContent data={data} index={0} />;
}
